import React, { useState, useRef, useEffect } from 'react';
import * as XLSX from 'xlsx';
import dbService from '../services/dbService';

// ----------------------------- INITIAL MOCK DATA -----------------------------
const DEFAULT_OFFICE_DATA = {
    'PSTO-Ilocos Norte': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        municipalities: ['Laoag City', 'Batac City', 'Pagudpud']
    },
    'PSTO-Ilocos Sur': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        municipalities: ['Vigan City', 'Candon City', 'Santa Maria']
    },
    'PSTO-La Union': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        municipalities: ['San Fernando', 'Bauang', 'Agoo', 'Luna', 'Bacnotan', 'Bangar', 'San Juan']
    },
    'PSTO-Pangasinan': {
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: '',
        municipalities: ['Lingayen', 'Dagupan', 'Alaminos']
    },
};

const DEFAULT_EVENTS = [];

const DEFAULT_USERS = [
    { id: 1, name: 'Admin User', email: 'admin@dostregion1.ph', office: 'PSTO-La Union', role: 'SADMIN', status: 'Active', password: 'admin123' },
    { id: 2, name: 'Regional Admin', email: 'admin-ilocosnorte@dostregion1.ph', office: 'PSTO-Ilocos Norte', role: 'ADMIN', status: 'Active', password: 'admin123' },
    { id: 3, name: 'General User', email: 'user-ilocossur@dostregion1.ph', office: 'PSTO-Ilocos Sur', role: 'USER', status: 'Active', password: 'user123' },
    { id: 4, name: 'La Union User', email: 'user-launion@dostregion1.ph', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: 'user123' },
    { id: 5, name: 'Pangasinan User', email: 'user-pangasinan@dostregion1.ph', office: 'PSTO-Pangasinan', role: 'USER', status: 'Active', password: 'user123' },
    { id: 6, name: 'Ilocos Sur User', email: 'user-ilocossur2@dostregion1.ph', office: 'PSTO-Ilocos Sur', role: 'USER', status: 'Active', password: 'user123' },
    { id: 7, name: 'Ilocos Norte User', email: 'user-ilocosnorte@dostregion1.ph', office: 'PSTO-Ilocos Norte', role: 'USER', status: 'Active', password: 'user123' },
];

// Helper functions
const loadFromStorage = (key, defaultValue) => {
    const stored = localStorage.getItem(key);
    if (stored) {
        try { return JSON.parse(stored); } catch (e) { return defaultValue; }
    }
    return defaultValue;
};

const saveToStorage = (key, data) => localStorage.setItem(key, JSON.stringify(data));

const archiveOldEvents = (events) => {
    const sevenDaysAgo = new Date();
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
    return events.map(event => {
        if (event.status !== 'archived' && event.endDateTime) {
            const endDate = new Date(event.endDateTime);
            if (endDate < sevenDaysAgo) {
                return { ...event, status: 'archived', deployment: event.deployment === 'Deployed' ? 'Draft' : event.deployment };
            }
        }
        return event;
    });
};

// Live weather fetch
const fetchLiveWeather = async () => {
    const lat = 16.5;
    const lon = 120.5;
    try {
        const response = await fetch(
            `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true&timezone=Asia/Manila`
        );
        const data = await response.json();
        if (data.current_weather) {
            const w = data.current_weather;
            const temp = w.temperature;
            const weatherCode = w.weathercode;
            let condition = '';
            if (weatherCode === 0) condition = 'Clear sky';
            else if (weatherCode === 1 || weatherCode === 2) condition = 'Partly cloudy';
            else if (weatherCode === 3) condition = 'Overcast';
            else if (weatherCode >= 45 && weatherCode <= 49) condition = 'Fog';
            else if (weatherCode >= 51 && weatherCode <= 67) condition = 'Drizzle / Rain';
            else if (weatherCode >= 71 && weatherCode <= 77) condition = 'Snow';
            else if (weatherCode >= 80 && weatherCode <= 99) condition = 'Rain / Thunderstorm';
            else condition = 'Unknown';
            return { temp: Math.round(temp), condition, windSpeed: w.windspeed };
        }
    } catch (err) {
        console.error('Weather fetch failed:', err);
    }
    return null;
};

const Dashboard = ({ onLogout, currentUser }) => {
    // ----------------------------- STATE -----------------------------
    const [officesData, setOfficesData] = useState(DEFAULT_OFFICE_DATA);
    const [events, setEvents] = useState(DEFAULT_EVENTS);
    const [users, setUsers] = useState(DEFAULT_USERS);
    const [pendingReports, setPendingReports] = useState([]);
    const [notifications, setNotifications] = useState([]);
    const [liveWeather, setLiveWeather] = useState(null);
    const [weatherLoading, setWeatherLoading] = useState(true);
    const [loading, setLoading] = useState(true);

    const [darkMode, setDarkMode] = useState(() => loadFromStorage('dash_darkMode', false));
    const [activeMenu, setActiveMenu] = useState('dashboard');
    const [selectedOffice, setSelectedOffice] = useState(currentUser?.office || 'PSTO-La Union');
    const [editMode, setEditMode] = useState(false);
    const [formData, setFormData] = useState(null);
    const [newMunicipality, setNewMunicipality] = useState('');
    const [newSignal, setNewSignal] = useState(1);
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState('all');
    const [showAddModal, setShowAddModal] = useState(false);
    const [showDetailsModal, setShowDetailsModal] = useState(false);
    const [selectedEvent, setSelectedEvent] = useState(null);
    const [isEditingEvent, setIsEditingEvent] = useState(false);
    const [isEditingReportLink, setIsEditingReportLink] = useState(false);
    const [reportLinkInput, setReportLinkInput] = useState('');
    const [showUserModal, setShowUserModal] = useState(false);
    const [isEditingUser, setIsEditingUser] = useState(false);
    const [userForm, setUserForm] = useState({ id: null, name: '', email: '', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: '' });
    const [userSearchTerm, setUserSearchTerm] = useState('');
    const [imageModalSrc, setImageModalSrc] = useState('');
    const [showImageModal, setShowImageModal] = useState(false);
    const [toast, setToast] = useState({ message: '', type: 'info', visible: false });
    const [rejectReason, setRejectReason] = useState('');
    const [showRejectModal, setShowRejectModal] = useState(false);
    const [rejectEventId, setRejectEventId] = useState(null);
    const [showReportModal, setShowReportModal] = useState(false);
    const [reportFormData, setReportFormData] = useState(null);
    const [selectedReport, setSelectedReport] = useState(null);
    const [showReportReviewModal, setShowReportReviewModal] = useState(false);
    const [reportRejectReason, setReportRejectReason] = useState('');
    const toastTimerRef = useRef(null);
    const [expandedSections, setExpandedSections] = useState({
        warningSignals: true,
        generalWeather: true,
        effects: true,
        remarks: true
    });

    const [newEvent, setNewEvent] = useState({
        id: null, name: '', startDateTime: '', endDateTime: '',
        alertLevel: '', category: '', deployment: 'Draft', provinces: [],
        sendToAllUsers: false, reportLink: '', trackPositions: '', intensity: '',
        related_incidents: 0, remark_related_incidents: '', casualties: 0, remark_casualties: '',
        power_status: '', remark_power_status: '', communication_lines: '', remark_communication_lines: '',
        damage_facilities: '', remark_damage_facilities: '', work_suspension: false,
        remark_work_suspension: '', assistance_provided: '', remark_assistance_provided: '',
        imageUrl: '', status: 'pending', rejectionReason: ''
    });

    // ----------------------------- LOAD DATA FROM DATABASE -----------------------------
    useEffect(() => {
        const loadData = async () => {
            setLoading(true);
            try {
                const [loadedOffices, loadedEvents, loadedUsers, loadedReports, loadedNotifs, savedMenu] = await Promise.all([
                    dbService.getOfficesData(),
                    dbService.getEvents(),
                    dbService.getUsers(),
                    dbService.getPendingReports(),
                    dbService.getNotifications(),
                    dbService.getActiveMenu()
                ]);

                if (loadedOffices && Object.keys(loadedOffices).length > 0) {
                    setOfficesData(loadedOffices);
                }

                if (loadedEvents && loadedEvents.length > 0) {
                    setEvents(archiveOldEvents(loadedEvents));
                }

                if (loadedUsers && loadedUsers.length > 0) {
                    setUsers(loadedUsers);
                }

                if (loadedReports && loadedReports.length > 0) {
                    setPendingReports(loadedReports);
                }

                if (loadedNotifs && loadedNotifs.length > 0) {
                    setNotifications(loadedNotifs);
                }

                if (savedMenu) setActiveMenu(savedMenu);

                console.log('Data loaded from database');
            } catch (error) {
                console.error('Error loading from database:', error);
                setOfficesData(loadFromStorage('dash_officesData', DEFAULT_OFFICE_DATA));
                setEvents(loadFromStorage('dash_events', DEFAULT_EVENTS));
                setUsers(loadFromStorage('dash_users', DEFAULT_USERS));
            } finally {
                setLoading(false);
            }
        };
        loadData();
    }, []);

    // ----------------------------- SAVE DATA TO DATABASE -----------------------------
    useEffect(() => {
        const saveToDatabase = async () => {
            if (!loading) {
                try {
                    await dbService.syncAllData({
                        officesData,
                        events,
                        users,
                        pendingReports,
                        notifications,
                        activeMenu
                    });
                } catch (error) {
                    console.error('Error saving to database:', error);
                    saveToStorage('dash_officesData', officesData);
                    saveToStorage('dash_events', events);
                    saveToStorage('dash_users', users);
                }
            }
        };
        const timeoutId = setTimeout(saveToDatabase, 2000);
        return () => clearTimeout(timeoutId);
    }, [officesData, events, users, pendingReports, notifications, activeMenu, loading]);

    // Save dark mode
    useEffect(() => {
        saveToStorage('dash_darkMode', darkMode);
        if (darkMode) {
            document.body.classList.add('dark-mode');
        } else {
            document.body.classList.remove('dark-mode');
        }
    }, [darkMode]);

    // Save active menu
    useEffect(() => {
        saveToStorage('dash_activeMenu', activeMenu);
        dbService.saveActiveMenu(activeMenu);
    }, [activeMenu]);

    // Fetch live weather
    useEffect(() => {
        const getWeather = async () => {
            setWeatherLoading(true);
            const weather = await fetchLiveWeather();
            setLiveWeather(weather);
            setWeatherLoading(false);
        };
        getWeather();
        const interval = setInterval(getWeather, 60000);
        return () => clearInterval(interval);
    }, []);

    const showToast = (message, type = 'info') => {
        if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
        setToast({ message, type, visible: true });
        toastTimerRef.current = setTimeout(() => {
            setToast(prev => ({ ...prev, visible: false }));
            toastTimerRef.current = null;
        }, 3200);
    };

    const addNotification = (title, message, type = 'info') => {
        const newNotif = {
            id: Date.now(),
            title,
            message,
            type,
            timestamp: new Date().toISOString(),
            read: false
        };
        setNotifications(prev => [newNotif, ...prev].slice(0, 50));
        showToast(message, type);
    };

    // Role helpers
    const rawRole = currentUser?.role ?? '';
    const normalizedRole = rawRole.toString().trim().toUpperCase();
    const isSuperAdmin = normalizedRole.includes('SADMIN') || normalizedRole.includes('SUPER ADMIN') || normalizedRole.includes('SUPERADMIN');
    const isAdmin = !isSuperAdmin && (normalizedRole === 'ADMIN' || normalizedRole.includes('ADMIN'));
    const isUser = normalizedRole === 'USER';
    const canManageUsers = isSuperAdmin;
    const canEditEvents = isSuperAdmin || isAdmin;
    const canDeployEvents = isSuperAdmin;
    const canRejectEvents = isSuperAdmin;
    const canApproveReports = isSuperAdmin;

    const allProvinces = ['Ilocos Norte', 'Ilocos Sur', 'La Union', 'Pangasinan'];
    const [activeEventId, setActiveEventId] = useState(() => {
        const active = events.find(e => e.deployment === 'Deployed')?.id || null;
        return active;
    });
    const activeEvent = events.find(e => e.id === activeEventId) || events.find(e => e.deployment === 'Deployed');

    const resetPSTODataForNewEvent = () => {
        const resetData = {};
        Object.keys(DEFAULT_OFFICE_DATA).forEach(office => {
            resetData[office] = {
                ...DEFAULT_OFFICE_DATA[office],
                warning_signals: {},
                general_weather: '',
                related_incidents: 0,
                casualties: 0,
                power_status: '',
                communication_lines: '',
                damage_facilities: '',
                work_suspension: false,
                assistance_provided: '',
                remark: '',
                remark_related_incidents: '',
                remark_casualties: '',
                remark_power_status: '',
                remark_communication_lines: '',
                remark_damage_facilities: '',
                remark_work_suspension: '',
                remark_assistance_provided: ''
            };
        });
        setOfficesData(resetData);
        addNotification('PSTO Data Reset', 'All PSTO warning signals and effects have been reset.', 'success');
    };

    // Event handlers
    const handleAddEvent = () => {
        if (!newEvent.name) { showToast('Event name is required.', 'warning'); return; }
        const newId = Math.max(...events.map(e => e.id), 0) + 1;
        const formattedDate = newEvent.startDateTime ? new Date(newEvent.startDateTime).toLocaleDateString() : new Date().toLocaleDateString();
        const provinces = newEvent.sendToAllUsers ? allProvinces : newEvent.provinces;
        setEvents([{ ...newEvent, id: newId, date: formattedDate, status: 'pending', provinces }, ...events]);
        resetNewEventForm();
        setShowAddModal(false);
        showToast('Event created.', 'success');
    };

    const resetNewEventForm = () => {
        setNewEvent({
            id: null, name: '', startDateTime: '', endDateTime: '',
            alertLevel: '', category: '', deployment: 'Draft', provinces: [],
            sendToAllUsers: false, reportLink: '', trackPositions: '', intensity: '',
            related_incidents: 0, remark_related_incidents: '', casualties: 0, remark_casualties: '',
            power_status: '', remark_power_status: '', communication_lines: '', remark_communication_lines: '',
            damage_facilities: '', remark_damage_facilities: '', work_suspension: false,
            remark_work_suspension: '', assistance_provided: '', remark_assistance_provided: '',
            imageUrl: '', status: 'pending', rejectionReason: ''
        });
    };

    const handleDeleteEvent = (eventId) => {
        if (!window.confirm('Delete this event?')) return;
        setEvents(events.filter(e => e.id !== eventId));
        setShowDetailsModal(false);
        showToast('Event deleted.', 'error');
    };

    const handleEditEvent = (event) => {
        setNewEvent(event);
        setIsEditingEvent(true);
        setShowAddModal(true);
        setShowDetailsModal(false);
    };

    const handleViewEvent = (event) => {
        setSelectedEvent(event);
        setShowDetailsModal(true);
    };

    const handleDeployEvent = (eventId) => {
        setEvents(events.map(e => ({
            ...e,
            deployment: e.id === eventId ? 'Deployed' : (e.deployment === 'Deployed' ? 'Draft' : e.deployment)
        })));
        showToast('Event deployed.', 'success');
    };

    const handleApproveEvent = (eventId) => {
        setEvents(events.map(e => e.id === eventId ? { ...e, status: 'approved' } : e));
        showToast('Event approved.', 'success');
    };

    const filteredEvents = events.filter(event => {
        const term = searchTerm.toLowerCase();
        return event.name.toLowerCase().includes(term) || (event.alertLevel || '').toLowerCase().includes(term);
    });

    // Report generation
    const handleGenerateReport = () => { showToast('Report generated.', 'success'); };
    const handleDownloadDoc = () => { showToast('DOC downloaded.', 'success'); };
    const handleExportExcel = () => { showToast('Excel exported.', 'success'); };

    // Reset/Export/Import
    const resetToDefaultData = () => {
        if (!isSuperAdmin) return;
        if (window.confirm('Reset all data?')) {
            setOfficesData(DEFAULT_OFFICE_DATA);
            setEvents(DEFAULT_EVENTS);
            setUsers(DEFAULT_USERS);
            showToast('Data reset.', 'success');
        }
    };

    const exportData = () => {
        const exportObj = { officesData, events, users };
        const dataStr = JSON.stringify(exportObj);
        const blob = new Blob([dataStr], { type: 'application/json' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `dashboard_backup_${Date.now()}.json`;
        a.click();
        URL.revokeObjectURL(url);
        showToast('Data exported.', 'success');
    };

    const importData = (e) => {
        const file = e.target.files[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (ev) => {
            try {
                const imported = JSON.parse(ev.target.result);
                if (imported.officesData) setOfficesData(imported.officesData);
                if (imported.events) setEvents(imported.events);
                if (imported.users) setUsers(imported.users);
                showToast('Data imported.', 'success');
            } catch (err) {
                showToast('Invalid file.', 'error');
            }
        };
        reader.readAsText(file);
        e.target.value = '';
    };

    // Helper functions for UI
    const getAlertColor = (level) => {
        const colors = { RED: '#dc3545', BLUE: '#007bff', WHITE: '#6c757d' };
        return colors[level] || '#28a745';
    };

    const getStatusColor = (status) => {
        const colors = { active: '#28a745', approved: '#0d6efd', pending: '#ffc107', draft: '#6c757d', rejected: '#dc3545' };
        return colors[status] || '#6c757d';
    };

    const getEventStatusLabel = (event) => {
        if (event.deployment === 'Deployed') return 'Active';
        if (event.status === 'pending') return 'Pending';
        if (event.status === 'approved') return 'Approved';
        return event.deployment || 'Draft';
    };

    const regionSummary = {
        incidents: Object.values(officesData).reduce((s, o) => s + (o.related_incidents || 0), 0),
        casualties: Object.values(officesData).reduce((s, o) => s + (o.casualties || 0), 0),
    };

    const displayWeather = liveWeather ? `${liveWeather.condition}, ${liveWeather.temp}°C` : 'Loading...';
    const unreadCount = notifications.filter(n => !n.read).length;

    // Handle office click
    const handleOfficeClick = (officeName) => {
        if (!isUser) setSelectedOffice(officeName);
    };

    const handleEditToggle = () => {
        if (!editMode) setFormData({ ...officesData[selectedOffice] });
        setEditMode(!editMode);
    };

    const handleSave = () => {
        setOfficesData({ ...officesData, [selectedOffice]: formData });
        setEditMode(false);
        showToast('Data saved.', 'success');
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData(prev => ({ ...prev, [name]: value }));
    };

    if (loading) {
        return <div className="loading-container"><div className="spinner"></div><p>Loading data from cloud...</p></div>;
    }

    // Settings Content
    const SettingsContent = () => {
        const [fontSize, setFontSize] = useState('medium');
        const handleFontSizeChange = (size) => {
            setFontSize(size);
            document.body.style.fontSize = size === 'small' ? '12px' : size === 'large' ? '16px' : '14px';
        };
        const handleClearData = () => {
            if (window.confirm('Clear all data?')) {
                localStorage.clear();
                window.location.reload();
            }
        };
        return (
            <div className="settings-container">
                <div className="events-header"><h1>Settings</h1></div>
                <div className="settings-section"><h3>Appearance</h3>
                    <div className="settings-card">
                        <div className="setting-item"><label>Dark Mode</label><button className={`setting-toggle ${darkMode ? 'active' : ''}`} onClick={() => setDarkMode(!darkMode)}>{darkMode ? 'Dark Mode On' : 'Light Mode On'}</button></div>
                        <div className="setting-item"><label>Font Size</label><div className="font-size-buttons"><button className={`font-btn ${fontSize === 'small' ? 'active' : ''}`} onClick={() => handleFontSizeChange('small')}>Small</button><button className={`font-btn ${fontSize === 'medium' ? 'active' : ''}`} onClick={() => handleFontSizeChange('medium')}>Medium</button><button className={`font-btn ${fontSize === 'large' ? 'active' : ''}`} onClick={() => handleFontSizeChange('large')}>Large</button></div></div>
                    </div>
                </div>
                <div className="settings-section"><h3>Data Management</h3>
                    <div className="settings-card">
                        <div className="setting-item"><label>Export Data</label><button className="secondary-btn" onClick={exportData}>Export</button></div>
                        <div className="setting-item"><label>Import Data</label><label className="import-btn-settings">Import<input type="file" onChange={importData} style={{ display: 'none' }} /></label></div>
                        <div className="setting-item"><label>Reset Data</label><button className="danger" onClick={resetToDefaultData}>Reset</button></div>
                        <div className="setting-item"><label>Clear Data</label><button className="danger" onClick={handleClearData}>Clear</button></div>
                    </div>
                </div>
            </div>
        );
    };

    // Dashboard Content (simplified)
    const DashboardContent = () => (
        <div>
            {toast.visible && <div className={`toast-banner toast-${toast.type}`}><span>{toast.message}</span><button className="toast-close" onClick={() => setToast(prev => ({ ...prev, visible: false }))}>×</button></div>}
            <div className="top-info-bar">
                <div className="top-info-item top-info-main"><span className="top-info-label">Current Event</span><span className="top-info-value">{activeEvent ? activeEvent.name : 'No Active Typhoon'}</span></div>
                <div className="top-info-item"><span className="top-info-label">Category</span><span className="top-info-value">{activeEvent?.category || '—'}</span></div>
                <div className="top-info-item"><span className="top-info-label">Alert Level</span><span className="top-info-value">{activeEvent?.alertLevel || '—'}</span></div>
                <div className="top-info-item"><span className="top-info-label">Live Weather</span><span className="top-info-value">{displayWeather}</span></div>
            </div>
            <div className="info-bar"><div className="info-item"><span className="info-value">Region 1</span></div><div className="info-item"><span className="info-label">Weather:</span><span className="info-value">{displayWeather}</span></div></div>
            <div className="notification-banner"><span className="notification-badge">SYSTEM NOTICE</span><span>Dashboard ready.</span>
                <div style={{ display: 'flex', gap: '10px' }}>
                    <button className="secondary-btn" onClick={handleGenerateReport}>Generate Report</button>
                    <button className="secondary-btn" onClick={handleDownloadDoc}>Download DOC</button>
                    <button className="secondary-btn" onClick={handleExportExcel}>Export Excel</button>
                </div>
            </div>
            <div className="psto-selector-section">
                <div className="psto-section-header"><h2>Select PSTO Office</h2></div>
                <div className="psto-selector-grid">
                    <div className={`psto-selector-card ${selectedOffice === 'PSTO-Region-1' ? 'active' : ''}`} onClick={() => handleOfficeClick('PSTO-Region-1')}><div className="psto-selector-name">PSTO Region 1</div><div className="psto-selector-stats"><span>{regionSummary.incidents}</span><span>{regionSummary.casualties}</span></div></div>
                    {Object.keys(officesData).map(office => (
                        <div key={office} className={`psto-selector-card ${selectedOffice === office ? 'active' : ''}`} onClick={() => handleOfficeClick(office)}><div className="psto-selector-name">{office}</div><div className="psto-selector-stats"><span>{officesData[office].related_incidents}</span><span>{officesData[office].casualties}</span></div></div>
                    ))}
                </div>
            </div>
            <div className="edit-controls-bar"><div><strong>Current PSTO:</strong> {selectedOffice}</div><div className="edit-buttons"><button onClick={handleEditToggle}>{editMode ? 'Cancel' : 'Edit PSTO Data'}</button>{editMode && <button className="success" onClick={handleSave}>Save</button>}</div></div>
        </div>
    );

    // Typhoon Content
    const TyphoonContent = () => (
        <div className="events-management">
            <div className="events-header"><h1>Manage Events</h1><div className="header-actions"><div className="search-box"><input type="text" placeholder="Search..." value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} /></div><button className="new-event-btn" onClick={() => setShowAddModal(true)}>+ New Event</button></div></div>
            <div className="events-table-container">
                <table className="events-table">
                    <thead><tr><th>EVENT NAME</th><th>DATE</th><th>ALERT LVL</th><th>STATUS</th><th>ACTIONS</th></tr></thead>
                    <tbody>
                        {filteredEvents.map(event => (
                            <tr key={event.id}>
                                <td className="event-name">{event.name}</td>
                                <td>{event.date}</td>
                                <td><span className="alert-badge" style={{ background: getAlertColor(event.alertLevel) }}>{event.alertLevel || '—'}</span></td>
                                <td><span className="status-badge" style={{ background: getStatusColor(event.status) }}>{getEventStatusLabel(event)}</span></td>
                                <td className="actions-cell">
                                    <button className="action-btn view-btn" onClick={() => handleViewEvent(event)}>View</button>
                                    <button className="action-btn" onClick={() => handleEditEvent(event)}>Edit</button>
                                    <button className="action-btn danger" onClick={() => handleDeleteEvent(event.id)}>Delete</button>
                                    {event.status === 'pending' && <button className="action-btn success" onClick={() => handleApproveEvent(event.id)}>Approve</button>}
                                    {event.status === 'approved' && <button className="action-btn deploy-btn" onClick={() => handleDeployEvent(event.id)}>Deploy</button>}
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
            {showAddModal && (<div className="modal-overlay" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}><div className="modal-content" onClick={e => e.stopPropagation()}><div className="modal-header"><h3>{isEditingEvent ? 'Edit Event' : 'Add Event'}</h3><button className="modal-close" onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>×</button></div><div className="form-group"><label>Event Name</label><input type="text" value={newEvent.name} onChange={(e) => setNewEvent({ ...newEvent, name: e.target.value })} /></div><div className="form-group"><label>Alert Level</label><select value={newEvent.alertLevel} onChange={(e) => setNewEvent({ ...newEvent, alertLevel: e.target.value })}><option>RED</option><option>BLUE</option><option>WHITE</option></select></div><div className="form-group"><label>Category</label><select value={newEvent.category} onChange={(e) => setNewEvent({ ...newEvent, category: e.target.value })}><option>Super Typhoon</option><option>Typhoon</option><option>Tropical Storm</option></select></div><div className="modal-buttons"><button className="success" onClick={handleAddEvent}>{isEditingEvent ? 'Save' : 'Create'}</button><button onClick={() => { setShowAddModal(false); setIsEditingEvent(false); }}>Cancel</button></div></div></div>)}
            {showDetailsModal && selectedEvent && (<div className="modal-overlay" onClick={() => setShowDetailsModal(false)}><div className="modal-content" onClick={e => e.stopPropagation()}><div className="modal-header"><h3>{selectedEvent.name}</h3><button className="modal-close" onClick={() => setShowDetailsModal(false)}>×</button></div><div><strong>Date:</strong> {selectedEvent.date}</div><div><strong>Alert Level:</strong> {selectedEvent.alertLevel}</div><div><strong>Category:</strong> {selectedEvent.category}</div><div><strong>Status:</strong> {selectedEvent.status}</div><div><strong>Provinces:</strong> {selectedEvent.provinces?.join(', ')}</div><div className="modal-buttons"><button onClick={() => setShowDetailsModal(false)}>Close</button></div></div></div>)}
        </div>
    );

    // Users Content
    const UsersContent = () => (
        <div className="events-management">
            <div className="events-header"><h1>User Management</h1><button className="new-event-btn" onClick={() => { setUserForm({ id: null, name: '', email: '', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: '' }); setIsEditingUser(false); setShowUserModal(true); }}>+ New User</button></div>
            <div className="events-table-container">
                <table className="events-table">
                    <thead><tr><th>Name</th><th>Email</th><th>Office</th><th>Role</th><th>Status</th><th>Actions</th></tr></thead>
                    <tbody>{users.map(user => (<tr key={user.id}><td>{user.name}</td><td>{user.email}</td><td>{user.office}</td><td>{user.role}</td><td>{user.status}</td><td className="actions-cell"><button className="view-btn" onClick={() => { setUserForm(user); setIsEditingUser(true); setShowUserModal(true); }}>Edit</button><button className="deploy-btn" onClick={() => { if (window.confirm('Delete user?')) setUsers(users.filter(u => u.id !== user.id)); }}>Delete</button></td></tr>))}</tbody>
                </table>
            </div>
            {showUserModal && (<div className="modal-overlay" onClick={() => setShowUserModal(false)}><div className="modal-content" onClick={e => e.stopPropagation()}><div className="modal-header"><h3>{isEditingUser ? 'Edit User' : 'Create User'}</h3><button className="modal-close" onClick={() => setShowUserModal(false)}>×</button></div><div className="form-group"><label>Name</label><input type="text" value={userForm.name} onChange={(e) => setUserForm({ ...userForm, name: e.target.value })} /></div><div className="form-group"><label>Email</label><input type="email" value={userForm.email} onChange={(e) => setUserForm({ ...userForm, email: e.target.value })} /></div><div className="form-group"><label>Office</label><select value={userForm.office} onChange={(e) => setUserForm({ ...userForm, office: e.target.value })}><option>PSTO-La Union</option><option>PSTO-Ilocos Norte</option><option>PSTO-Ilocos Sur</option><option>PSTO-Pangasinan</option></select></div><div className="form-group"><label>Password</label><input type="password" value={userForm.password} onChange={(e) => setUserForm({ ...userForm, password: e.target.value })} /></div><div className="form-group"><label>Role</label><select value={userForm.role} onChange={(e) => setUserForm({ ...userForm, role: e.target.value })}><option>SADMIN</option><option>ADMIN</option><option>USER</option></select></div><div className="form-group"><label>Status</label><select value={userForm.status} onChange={(e) => setUserForm({ ...userForm, status: e.target.value })}><option>Active</option><option>Inactive</option></select></div><div className="modal-buttons"><button className="success" onClick={() => { if (isEditingUser) { setUsers(users.map(u => u.id === userForm.id ? userForm : u)); } else { setUsers([{ ...userForm, id: Date.now() }, ...users]); } setShowUserModal(false); }}>{isEditingUser ? 'Save' : 'Create'}</button><button onClick={() => setShowUserModal(false)}>Cancel</button></div></div></div>)}
        </div>
    );

    const NotificationsContent = () => (
        <div className="events-management">
            <div className="events-header"><h1>Notifications {unreadCount > 0 && `(${unreadCount} new)`}</h1><button className="new-event-btn" onClick={() => setNotifications([])}>Clear All</button></div>
            <div className="notifications-list">{notifications.length === 0 ? <div className="no-notifications">No notifications.</div> : notifications.map(notif => (<div key={notif.id} className={`notification-item ${!notif.read ? 'unread' : ''}`} onClick={() => setNotifications(prev => prev.map(n => n.id === notif.id ? { ...n, read: true } : n))}><div className="notification-header"><span>{notif.title}</span><span>{new Date(notif.timestamp).toLocaleString()}</span></div><div>{notif.message}</div></div>))}</div>
        </div>
    );

    const PendingReportsContent = () => <div className="events-management"><div className="events-header"><h1>Pending Reports</h1></div><div>Coming soon...</div></div>;

    // MAIN RENDER
    return (
        <div className={`dashboard-container ${darkMode ? 'dark-theme' : ''}`}>
            <div className="sidebar-new">
                <div className="sidebar-logo"><h2>DOST Region 1</h2><p>Disaster Management</p></div>
                <nav className="sidebar-nav">
                    <div className={`nav-item ${activeMenu === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveMenu('dashboard')}><span className="nav-icon">📊</span><span>Dashboard</span></div>
                    <div className={`nav-item ${activeMenu === 'typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('typhoon')}><span className="nav-icon">🌊</span><span>Typhoon</span></div>
                    <div className={`nav-item ${activeMenu === 'live-typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('live-typhoon')}><span className="nav-icon">🗺️</span><span>Live Typhoon</span></div>
                    <div className={`nav-item ${activeMenu === 'notifications' ? 'active' : ''}`} onClick={() => setActiveMenu('notifications')}><span className="nav-icon">🔔</span><span>Notifications</span></div>
                    <div className={`nav-item ${activeMenu === 'settings' ? 'active' : ''}`} onClick={() => setActiveMenu('settings')}><span className="nav-icon">⚙️</span><span>Settings</span></div>
                    {canApproveReports && <div className={`nav-item ${activeMenu === 'pending-reports' ? 'active' : ''}`} onClick={() => setActiveMenu('pending-reports')}><span className="nav-icon">📋</span><span>Pending Reports</span></div>}
                    {canManageUsers && <div className={`nav-item ${activeMenu === 'users' ? 'active' : ''}`} onClick={() => setActiveMenu('users')}><span className="nav-icon">👥</span><span>Users</span></div>}
                </nav>
                <div className="sidebar-footer">
                    <div className="user-info"><div className="user-greeting">Hello, {currentUser?.name || 'Admin'}</div><div className="user-role">{isSuperAdmin ? 'SUPER ADMIN' : (isAdmin ? 'ADMIN' : 'USER')}</div></div>
                    <div className="user-actions"><div className="action-item logout" onClick={onLogout}>🚪 Logout</div></div>
                </div>
            </div>
            <div className="main-content">
                {isSuperAdmin && (<div className="admin-toolbar"><button onClick={resetToDefaultData}>Reset Data</button><button onClick={exportData}>Export</button><label className="import-btn">Import<input type="file" onChange={importData} style={{ display: 'none' }} /></label></div>)}
                {activeMenu === 'dashboard' && <DashboardContent />}
                {activeMenu === 'typhoon' && <TyphoonContent />}
                {activeMenu === 'live-typhoon' && (<div className="forecast-section card"><h1>Live Typhoon</h1><div className="windy-embed-container"><iframe title="Panahon" src="https://www.panahon.gov.ph/" frameBorder="0" allowFullScreen /></div></div>)}
                {activeMenu === 'notifications' && <NotificationsContent />}
                {activeMenu === 'settings' && <SettingsContent />}
                {activeMenu === 'pending-reports' && <PendingReportsContent />}
                {activeMenu === 'users' && <UsersContent />}
            </div>
        </div>
    );
};

export default Dashboard;
